import{_ as a,o as t,c as o,a3 as r}from"./chunks/framework.Df0_fMVA.js";const m=JSON.parse('{"title":"Introducao","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/guide/introduction.md","filePath":"pt-BR/guide/introduction.md"}'),d={name:"pt-BR/guide/introduction.md"};function s(i,e,n,c,l,u){return t(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="introducao" tabindex="-1">Introducao <a class="header-anchor" href="#introducao" aria-label="Permalink to &quot;Introducao&quot;">​</a></h1><h2 id="o-problema" tabindex="-1">O Problema <a class="header-anchor" href="#o-problema" aria-label="Permalink to &quot;O Problema&quot;">​</a></h2><p>Assistentes de IA para codigo sao generalistas. Eles escrevem codigo, mas nao aplicam arquitetura, nao seguem os padroes do seu time, e nao pegam o que um engenheiro senior pegaria.</p><p>Voce acaba:</p><ul><li>Re-explicando as mesmas convencoes a cada sessao</li><li>Recebendo codigo que &quot;funciona&quot; mas nao segue sua arquitetura</li><li>Perdendo problemas de seguranca, performance ou compliance</li><li>Fazendo code review manual em codigo gerado por IA</li></ul><h2 id="a-solucao" tabindex="-1">A Solucao <a class="header-anchor" href="#a-solucao" aria-label="Permalink to &quot;A Solucao&quot;">​</a></h2><p>Specialist Agent da ao seu assistente de IA um time de especialistas. Em vez de um generalista, voce tem:</p><ul><li><strong>@builder</strong> que conhece os padroes de componentes do seu framework</li><li><strong>@reviewer</strong> que aplica SOLID, seguranca e regras de arquitetura</li><li><strong>@security</strong> que detecta problemas do OWASP Top 10</li><li><strong>@sentry-triage</strong> que faz triagem de erros em producao automaticamente</li></ul><p>Cada agente carrega conhecimento, regras e fluxos de trabalho especificos. Eles nao apenas escrevem codigo — eles aplicam padroes.</p><h2 id="como-funciona" tabindex="-1">Como Funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Como Funciona&quot;">​</a></h2><p>Voce instala os agentes no seu projeto. Quando precisa de algo, chama o agente certo:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; Use @builder to create the products module with CRUD</span></span>
<span class="line"><span>&gt; Use @sentry-triage to check errors from the last 24h</span></span>
<span class="line"><span>&gt; Use @reviewer to review src/modules/auth/</span></span>
<span class="line"><span>&gt; /plan add real-time notifications with WebSocket</span></span></code></pre></div><h2 id="categorias-de-agentes" tabindex="-1">Categorias de Agentes <a class="header-anchor" href="#categorias-de-agentes" aria-label="Permalink to &quot;Categorias de Agentes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Categoria</th><th>Agentes</th><th>Proposito</th></tr></thead><tbody><tr><td><strong>Core</strong></td><td>5</td><td>Construir, revisar, debugar, migrar</td></tr><tr><td><strong>Workflow</strong></td><td>9</td><td>Planejar, executar, testar, pair programming</td></tr><tr><td><strong>Engenharia</strong></td><td>17</td><td>API, seguranca, dados, DevOps, arquitetura</td></tr><tr><td><strong>Negocios</strong></td><td>3</td><td>Marketing, produto, suporte</td></tr><tr><td><strong>Automacao</strong></td><td>1</td><td>Triagem Sentry, correcao automatica de erros em producao</td></tr></tbody></table><h2 id="skills" tabindex="-1">Skills <a class="header-anchor" href="#skills" aria-label="Permalink to &quot;Skills&quot;">​</a></h2><p>Skills sao workflows repetiveis que voce invoca com um comando de barra:</p><table tabindex="0"><thead><tr><th>Categoria</th><th>Skills</th></tr></thead><tbody><tr><td>Planejamento</td><td><code>/brainstorm</code>, <code>/plan</code>, <code>/discovery</code>, <code>/estimate</code></td></tr><tr><td>Desenvolvimento</td><td><code>/tdd</code>, <code>/debug</code>, <code>/autofix</code>, <code>/lint</code>, <code>/commit</code></td></tr><tr><td>Qualidade</td><td><code>/verify</code>, <code>/codereview</code>, <code>/audit</code>, <code>/health</code></td></tr><tr><td>Workflow</td><td><code>/checkpoint</code>, <code>/finish</code>, <code>/worktree</code>, <code>/learn</code></td></tr><tr><td>Migracao</td><td><code>/migrate-framework</code>, <code>/migrate-architecture</code></td></tr><tr><td>Conhecimento</td><td><code>/remember</code>, <code>/recall</code>, <code>/onboard</code>, <code>/tutorial</code>, <code>/write-skill</code></td></tr></tbody></table><h2 id="o-que-diferencia" tabindex="-1">O que Diferencia <a class="header-anchor" href="#o-que-diferencia" aria-label="Permalink to &quot;O que Diferencia&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>IA Generica</th><th>Specialist Agent</th></tr></thead><tbody><tr><td>Aplicacao de arquitetura</td><td>Nao</td><td>Agentes aplicam seu ARCHITECTURE.md</td></tr><tr><td>Padroes de framework</td><td>Generico</td><td>7 packs de framework com agentes otimizados</td></tr><tr><td>Profundidade de review</td><td>Superficial</td><td>Review 3-em-1 (qualidade + seguranca + arquitetura)</td></tr><tr><td>Ops em producao</td><td>Manual</td><td>@sentry-triage faz triagem automatica</td></tr><tr><td>Agentes de negocio</td><td>Nao</td><td>@marketing, @product, @support</td></tr><tr><td>Fluxos repetitivos</td><td>Manual</td><td>24 skills (/plan, /tdd, /autofix, ...)</td></tr><tr><td>Multi-plataforma</td><td>Varia</td><td>6 plataformas suportadas</td></tr></tbody></table><h2 id="packs-de-frameworks" tabindex="-1">Packs de Frameworks <a class="header-anchor" href="#packs-de-frameworks" aria-label="Permalink to &quot;Packs de Frameworks&quot;">​</a></h2><p>Cada framework recebe agentes otimizados com padroes especificos:</p><p><strong>Vue 3</strong> | <strong>React</strong> | <strong>Next.js</strong> | <strong>SvelteKit</strong> | <strong>Angular</strong> | <strong>Astro</strong> | <strong>Nuxt</strong></p><h2 id="plataformas-suportadas" tabindex="-1">Plataformas Suportadas <a class="header-anchor" href="#plataformas-suportadas" aria-label="Permalink to &quot;Plataformas Suportadas&quot;">​</a></h2><p>Funciona em: <strong>Claude Code</strong>, <strong>Cursor</strong>, <strong>VS Code</strong>, <strong>Windsurf</strong>, <strong>Codex</strong>, <strong>OpenCode</strong></p><h2 id="para-quem" tabindex="-1">Para Quem <a class="header-anchor" href="#para-quem" aria-label="Permalink to &quot;Para Quem&quot;">​</a></h2><ul><li><strong>Devs solo</strong> que querem review de nivel senior em cada commit</li><li><strong>Times</strong> que querem padronizar como a IA auxilia o desenvolvimento</li><li><strong>Startups</strong> que precisam ir rapido sem acumular divida tecnica</li><li><strong>Enterprise</strong> que precisa de compliance, seguranca e aplicacao de arquitetura</li></ul><h2 id="proximos-passos" tabindex="-1">Proximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Proximos Passos&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-79/pt-BR/guide/quick-start.html">Quick Start</a> — Instale e use seu primeiro agente</li><li><a href="/pr-preview/pr-79/pt-BR/reference/agents.html">Catalogo de Agentes</a> — Todos os 35 agentes</li><li><a href="/pr-preview/pr-79/pt-BR/reference/skills.html">Referencia de Skills</a> — Todas as 24 skills</li></ul>`,28)])])}const g=a(d,[["render",s]]);export{m as __pageData,g as default};
